._tell-amazon-desktop_style_tell_amazon_component_preload__2jBs4{displaynone}._tell-amazon-desktop_style_tell_amazon_thankyou_page__1PP1x{displaynone;margin-bottom60px;padding30px 15px}._tell-amazon-desktop_style_tell_amazon_dropdown__3USiH{margin-top10px}._tell-amazon-desktop_style_tell_amazon_dropdown_label__2ydKL{margin-bottom5px}._tell-amazon-desktop_style_alert_type__34m2d{displaynone}._tell-amazon-desktop_style_tell_amazon_freeform_text__DOb62{margin10px 0}._tell-amazon-desktop_style_tell_amazon_try_again_message__3L5ej{displaynone;floatleft}._tell-amazon-desktop_style_tell_amazon_checkbox_component__2mOqM{margin10px 0}._tell-amazon-desktop_style_tell_amazon_checkbox_template__2Bgy6{displaynone}._tell-amazon-desktop_style_tell_amazon_input_template__26G48{displaynone}._tell-amazon-desktop_style_tell_amazon_input__30pRm{margin-bottom10px}: Relatar um problema com este produto | /*
     * Used when device = desktop
     * Configured in configuration/brazil-config/global/brand-story.cfg
     */

    /* Because the carousel is implemented as an ol list,
       any lists in the card text will have a secondary list style (letters).
       This will give an incorrect appearance to viewers,
       so we set all lists to the primary list style (numbers). */
    .aplus-brand-story-card ol li {
        list-style decimal;
    }

    /* Top level containers */
    .aplus-module .apm-brand-story-hero {
      -moz-box-sizing border-box;
      -webkit-box-sizing border-box;
      box-sizing border-box;
      width 1464px;
      height 625px;
      background-color #fff;
    }

    .aplus-module .apm-brand-story-card {
      -moz-box-sizing border-box;
      -webkit-box-sizing border-box;
      box-sizing border-box;
      width 362px;
      height 453px;
      background-color #fff;
    }

    .apm-brand-story-hero,
    .apm-brand-story-card {
      -moz-box-sizing border-box;
      -webkit-box-sizing border-box;
      box-sizing border-box;
      position relative;
      width 100%;
      height 100%;
      float none;
    }

    .aplus-module.brand-story-card-1-four-asin .apm-brand-story-card {
      /* Only 12px to account for image cell border */
      padding 12px;
    }

    /* Full background image (Hero 1 & Card 2) */
    .aplus-module .apm-brand-story-background-image {
      -moz-box-sizing border-box;
      -webkit-box-sizing border-box;
      box-sizing border-box;
      overflow hidden;
      position absolute;
      width 100%;
      height 100%;
    }

    .aplus-module .apm-brand-story-background-image img {
      display block;
      width 100%;
      height 100%;
      object-fit cover;
    }

    /* Card 1 small images */
    .aplus-module .apm-brand-story-image-grid {
      -moz-box-sizing border-box;
      -webkit-box-sizing border-box;
      box-sizing border-box;
      padding 0px;
      margin auto;
      display flex;
      flex-flow row wrap;
    }

    .aplus-module .apm-brand-story-image-grid .apm-brand-story-image-grid-item {
      /* Use content-box to ensure image size matches editor schema */
      -moz-box-sizing content-box;
